int berechneDifferenz (int zaehlerstandAlt, int zaehlerstandNeu) {
    int differenz = -1;

    if (zaehlerstandAlt >= 0 && zaehlerstandNeu > 0) {
        if (zaehlerstandAlt < zaehlerstandNeu) {
            differenz = zaehlerstandNeu - zaehlerstandAlt;
        }
    }
    return differenz;
}

@Test
void testeBerechneDifferenz() {
    assertEquals(20, berechneDifferenz(240, 260));
    assertEquals(0, berechneDifferenz(120, 120));
    assertEquals(0, berechneDifferenz(0, 0));
    assertEquals(80, berechneDifferenz(0, 80));
    assertEquals(-1, berechneDifferenz(440, 420));
}

